import { latLng, LatLng } from 'leaflet';
import React, { useMemo } from 'react';
import { Polyline, Tooltip } from 'react-leaflet';

import Data from '../json/data.json';

import { RouteData } from './App';
// -------------------------------------------------------------------------
// 表示に使用する値系。
// -------------------------------------------------------------------------

// レベルを元にした、地図で表示する線の色。
const colorFromLevel = [
  'hsl(220,30%,20%)', // 0: 黒
  'hsl(240,70%,50%)', // 1: 青
  'hsl(140,50%,50%)', // 2: 緑
  'hsl(30,80%,60%)', // 3: 橙
  'hsl(0,80%,60%)', // 4: 赤
  'hsl(290,70%,50%)', // 5: 紫
];

// -------------------------------------------------------------------------

/**
 * データの座標のリストを、表示用の座標のリストへ変換する。
 * @param coordinates
 * @returns
 */
const latLngsFromCoordinates = (coordinates: number[][]) => {
  let array: Array<LatLng> = [];

  for (const c of coordinates) {
    array.push(latLng(c[0], c[1]));
  }

  return array;
};

/**
 * 1つのルートのデータのキーを返す。
 * @param data
 * @returns
 */
const keyFromRoute = (data: RouteData): string => {
  // 座標がなかったときは名前だけを返す。
  if (data.coordinates.length === 0) {
    return `${data.name}-0-0`;
  }

  return `${data.name}-${data.coordinates[0][0]}-${data.coordinates[0][1]}`;
};

// -------------------------------------------------------------------------

/**
 * データを元に、地図に表示する情報（線）を生成する。
 * @param route
 * @returns
 */
const ItemFromRouteData = (
  route: RouteData,
  selected: RouteData | null,
  setRoute: React.Dispatch<React.SetStateAction<RouteData | null>>,
) => {
  const ll = latLngsFromCoordinates(route.coordinates);

  const color = colorFromLevel[route.gravelLevel];
  const lineOptions = {
    color,
    weight: 6,
    opacity: 0.6,
  };
  const highlightLineOptions = {
    color: color,
    weight: 20,
    opacity: 0.5,
  };

  const gra = ` ${'★'.repeat(route.gravelLevel)}`;

  const tooltip = `${route.name}${gra}`;

  const key = keyFromRoute(route); //`${data.name}-$[data.lat]`;

  // 線がクリックされたときに呼び出されるコールバック。
  // 当該の詳細情報を表示する。
  const eventHandlers = {
    click: () => {
      setRoute(route);
    },
  };
  // ここは元々 useMemo していたけど、恐らく不要なので削除。
  // const eventHandlers = useMemo(
  //   () => ({
  //     click() {
  //       setData(data);
  //     },
  //   }),
  //   [data, setData],
  // );

  let selectedFlag = false;

  if (selected != null && key === keyFromRoute(selected!)) {
    selectedFlag = true;
  }

  return (
    <>
      {selectedFlag && (
        <Polyline
          positions={ll}
          pathOptions={highlightLineOptions}
          key={key + 'h'}
        ></Polyline>
      )}
      <Polyline
        positions={ll}
        pathOptions={lineOptions}
        eventHandlers={eventHandlers}
        key={key}
      >
        <Tooltip direction="top" key={key + 't'}>
          {tooltip}
        </Tooltip>
      </Polyline>
    </>
  );
};

// -------------------------------------------------------------------------

/**
 * 地図に表示する情報のコンポーネント。
 * @returns
 */
export const Items = (props: {
  selectedRoute: RouteData | null;
  setRoute: React.Dispatch<React.SetStateAction<RouteData | null>>;
}) => {
  // メモ化しているけど、最初の1回しか呼び出されていないので不要かも。
  const routes = useMemo(() => Data.routes, []);
  // console.log('Items updated');

  const routeItems = [];
  for (const r of routes) {
    // 座標が空だったらスキップする。
    if (r.coordinates.length === 0 || r.coordinates[0].length === 0) {
      continue;
    }

    routeItems.push(
      ItemFromRouteData({ ...r }, props.selectedRoute, props.setRoute),
    );
  }

  return (
    <>
      {routeItems}
      {/* <Polyline positions={line1} pathOptions={lineOptions}>
        <Tooltip direction="top">
          ツール<b>チップ</b>
        </Tooltip>
      </Polyline> */}
    </>
  );
};
