import { RouteData } from './App';
import './App.css';

// -------------------------------------------------------------------------

const gravelLevelComment = [
  '',
  'ロードバイクでも余裕で走れるレベル。フラットダート等。',
  'グラベルロードなら余裕、ロードバイクでは走行に気を使うレベル。小さな石の砂利道等。',
  'グラベルロードでも気を使わなければならないレベル。',
  'グラベルロードでも苦労するレベル。大きい石等。',
  'MTBレベル。荒れた道等。',
];

const widthLevelComment = [
  '',
  'シングルトラック。クルマは走行不能。',
  'ダブルトラック。クルマ1台が走行可能。',
  '1.5車線。クルマ同士は避け合えばすれ違いが可能。',
  '2車線。クルマが普通にすれ違い可能。',
  'それ以上。広場等。',
];

// レベルを元にした背景色。
const levelBackgroundColor = [
  'hsl(220,0%,20%)', // 0: 黒
  'hsl(210,60%,20%)', // 1: 青
  'hsl(140,40%,20%)', // 2: 緑
  'hsl(30,80%,20%)', // 3: 橙
  'hsl(0,70%,20%)', // 4: 赤
  'hsl(290,40%,20%)', // 5: 紫
];
// const levelBackgroundColor = [
//   'hsl(220,0%,80%)', // 0: 黒
//   'hsl(210,30%,80%)', // 1: 青
//   'hsl(140,20%,80%)', // 2: 緑
//   'hsl(30,50%,80%)', // 3: 橙
//   'hsl(0,50%,90%)', // 4: 赤
//   'hsl(290,40%,80%)', // 5: 紫
// ];

// -------------------------------------------------------------------------

type Props = {
  route: RouteData | null;
};

export const InformationBox = (props: Props) => {
  if (props.route == null) {
    return (
      <div id="information-box">
        データなし
        <br />
        地図から選択してください
      </div>
    );
  }

  // グラベル度。星の部分の幅を5文字にするためにスペースを追加している。
  const gra =
    props.route.gravelLevel != null ? (
      <tr>
        <td>グラベル度</td>
        <td>{props.route.gravelLevel}</td>
        <td title={gravelLevelComment[props.route.gravelLevel]}>
          {'★'.repeat(props.route.gravelLevel)}
          {'　'.repeat(5 - props.route.gravelLevel)}
        </td>
      </tr>
    ) : (
      <tr>
        <td>グラベル度</td>
        <td>?</td>
        <td></td>
      </tr>
    );

  const wid =
    props.route.widthLevel != null ? (
      <tr>
        <td>道幅</td>
        <td>{props.route.widthLevel}</td>
        <td title={widthLevelComment[props.route.widthLevel]}>
          {'★'.repeat(props.route.widthLevel)}
          {'　'.repeat(5 - props.route.widthLevel)}
        </td>
      </tr>
    ) : (
      <tr>
        <td>道幅</td>
        <td>?</td>
        <td></td>
      </tr>
    );

  const slo =
    props.route.slopeLevel != null ? (
      <tr>
        <td>勾配度</td>
        <td>{props.route.slopeLevel}</td>
        <td>
          {'★'.repeat(props.route.slopeLevel)}
          {'　'.repeat(5 - props.route.slopeLevel)}
        </td>
      </tr>
    ) : (
      <tr>
        <td>勾配度</td>
        <td>?</td>
        <td></td>
      </tr>
    );

  const thr =
    props.route.through != null ? (
      <tr>
        <td>通り抜け</td>
        <td></td>
        <td>{props.route.through ? '○' : '×'}</td>
      </tr>
    ) : (
      <></>
    );

  // 説明文。元データのHTMLタグを反映させている。
  const des =
    props.route.description != null ? (
      <div
        className="description"
        dangerouslySetInnerHTML={{ __html: props.route.description }}
      ></div>
    ) : (
      <div></div>
    );

  // Google Mapsへのリンク。座標リストの真ん中あたりを表示する。
  const [lat, lng] = centerFromCoordinates(props.route.coordinates);
  const link = `https://www.google.co.jp/maps?q=${lat},${lng}&z=19&t=k`;
  const googleMapLink = (
    <a href={link} target="_blank" rel="noreferrer">
      Google Mapsで表示
    </a>
  );

  return (
    <div
      id="information-box"
      style={{ background: levelBackgroundColor[props.route.gravelLevel] }}
    >
      <div className="title">{props.route.name}</div>
      <table>
        <tbody>
          {gra}
          {wid}
          {slo}
          {thr}
        </tbody>
      </table>
      {des}
      {googleMapLink}
    </div>
  );
};

// -------------------------------------------------------------------------

// 座標リストを元に、中心っぽい位置を算出して返す。
const centerFromCoordinates = (coordinates: number[][]): [number, number] => {
  if (coordinates.length === 0) {
    // 座標が0個の場合は適当な位置を返す。
    return [35.58, 139.34];
  } else if (coordinates.length === 1) {
    // 座標が1個だけのときはその値を返す。
    return [coordinates[0][0], coordinates[0][1]];
  } else if (coordinates.length === 2) {
    // 座標が2個のときはその中間を返す。
    const lat = (coordinates[0][0] + coordinates[1][0]) / 2;
    const lng = (coordinates[0][1] + coordinates[1][1]) / 2;
    return [lat, lng];
  } else {
    // 座標が3個以上のときは、真ん中あたりの座標を返す。
    // （座標を矩形にしてその中央みたいにすると、軌跡と異なる位置を示してしまうので、この動作にしている）
    const index = Math.trunc((coordinates.length - 1) / 2);
    return [coordinates[index][0], coordinates[index][1]];
  }
};
